var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 상업 지구, <color=#ffd34c>본선 2 경기</color>","JPN":"シャレード商業地区、<color=#ffd34c>本戦第3試合</color>","ENG":"Charade Commercial District, <color=#ffd34c>Second elimination match</color>","TWN":"查雷德商業區，<color=#ffd34c>淘汰賽進行中</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아아, 본선 제3 경기가 진행되는 가운데, 흐름은 팩토리 측이 압도적──!!","JPN":"ああ、本戦第3試合が行われている中、ファクトリー側が圧倒的にリードしています！！","ENG":"Ahh, as the third match of the eliminations starts, Factory has the upper hand!!","TWN":"啊啊，第三場比賽正在進行中，工業隊佔據了壓倒性的優勢──！！"},"stage":{"bg":"JIA_SPECIAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"텍티칼 사의 에이스가 빠져서 경기력 차이가 너무 확연하다구!","JPN":"テクティカル社のエースが抜けて、戦力差が著しい！","ENG":"Without Tactical's ace, the difference in power is just too much!","TWN":"裝備公司的王牌缺席，實力差距太明顯了！"},"stage":{"bg":"JIA_SPECIAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"갑자기 무단으로 경기에 불참했다던데, 이유가 뭘까?","JPN":"突然出場を取り消したみたいだけど、理由はなんだろう？","ENG":"Why did their ace suddenly drop out, I wonder.","TWN":"聽說他突然擅自缺席比賽，原因是什麼呢？"},"stage":{"bg":"JIA_SPECIAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 쫄아서 도망갔나 보지 ㅋㅋㅋㅋ\\n<color=#ffd34c>■■</color> 카운터면 다야? 그래서 내 돈 어쩔 거냐고!!\\n<color=#ffd34c>■■■■</color> 텍티칼에 건 네 잘못이지 ㅋㅋㅋㅋ\\n<color=#ffd34c>■■■</color> 어차피 건틀렛은 스폰서 싸움이라고ㅋㅋ\\n<color=#ffd34c>■■■</color> 플라티나가 밀어주는 팩토리가 정배지 ㅋㅋㅋ","JPN":"<color=#ffd34c>■■■</color> ビビッて逃げたんじゃねーのｗｗｗｗ\\n<color=#ffd34c>■■</color> カウンターなら何でもありかよ？　俺の金どうしてくれんだよ！\\n<color=#ffd34c>■■■■</color> テクティカルに賭けたやつがバカだろｗｗｗｗ\\n<color=#ffd34c>■■■</color> どうせガントレットはスポンサー対決なんだぜｗｗ\\n<color=#ffd34c>■■■</color> プラチナが推してるファクトリーが勝つに決まってんだろｗｗｗ","ENG":"<color=#ffd34c>■■■</color> Got scared and ran LOL\\n<color=#ffd34c>■■</color> Counter, my foot! What about my money?!\\n<color=#ffd34c>■■■■</color> Your fault for betting on Tactical LMAO!\\n<color=#ffd34c>■■■</color> Gauntlet is about who has the better sponsor anyway HAHA\\n<color=#ffd34c>■■■</color> With Platina supporting Factory, the winner's already been chosen!","TWN":"<color=#ffd34c>■■■</color> 嚇得逃跑了嗎，哈哈哈\\n<color=#ffd34c>■■</color> 你以為是制裁者就行了嗎？那我的錢怎麼辦！！\\n<color=#ffd34c>■■■■</color> 當然是你押裝備公司的錯囉，哈哈哈\\n<color=#ffd34c>■■■</color> 反正聖鎧就是贊助商打架嘛，哈哈\\n<color=#ffd34c>■■■</color> 有白金支持，工業隊贏定了吧，哈哈"},"stage":{"bg":"JIA_SPECIAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아, 말씀드리는 순간, 본선 제3 경기는 팩토리 측의 승리──!!","JPN":"あー！　本戦第3試合、ファクトリー側が勝利を収めましたー！！","ENG":"Oh, and just as I was about to answer, the third match goes to Factory!!","TWN":"啊，就在說話的瞬間，第3場比賽由工業隊方獲勝──！！"},"stage":{"bg":"JIA_SPECIAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"자자, 텍티칼에 건 녀석들은 얼른 돈이나 뱉어내라고?","JPN":"ささ、テクティカルに賭けたやつら！　金を寄こせ！","ENG":"All right, everyone who bet on Tactical, get ready to pay up, okay?","TWN":"來來，下錯注的傢伙們，趕緊把錢交出來吧？"},"stage":{"bg":"JIA_SPECIAL","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 어째서……. 침식체가……?","JPN":"ど、どうして……侵食体が……？","ENG":"W-why is... there a C.O....?","TWN":"啊，為什麼……侵蝕體……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"크윽……! 끄으윽……! 아아아아아아아악……!!","JPN":"くっ……！　くううっ……！　ああああああああ……！！","ENG":"Gah...! Errgh...! AAAARRRRRGH...!!","TWN":"呵呃……！呃呃呃……！啊啊啊啊啊啊啊啊……！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_09"},{"id":"L21_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"경기 승리는 확인했다. 녀석은 어떻게 됐지?","JPN":"試合の勝利は確認した。やつはどうした？","ENG":"I saw the results of the match. What happened to him?","TWN":"我看到比賽結果了。那傢伙怎麼樣了？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L25_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"명령대로. 죽이고. 먹었다.","JPN":"命令ドオリ。殺シテ、食ベタ。","ENG":"As ordered. I killed. Then ate.","TWN":"按照你說的。殺了。吃了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"시체. 없으면 발각되지 않는다. 인간. 쫓지 않는다.","JPN":"死体。ナイト見ツカラナイ。人間。追ワナイ。","ENG":"No corpse. Found. Humans. Don't chase.","TWN":"沒有屍體。不會發現。人類。追蹤不了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"흠, 꼴좋군.","JPN":"ふむ、ざまあ見ろ。","ENG":"Hmm, serves him right.","TWN":"哼，活該。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"에이스라고 조금 띄워줬더니 건방지게 이적을 해?","JPN":"エースだからと優遇してやったのに移籍だと？　生意気な。","ENG":"How dare he transfer to another team after we praised him a little as our ace.","TWN":"把你捧成王牌，竟然敢明目張膽地跳槽？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그러게 계약금 올려준다고 했을 때, 얌전히 받아들였어야지.","JPN":"契約金を上げてやると言った時、大人しく受け入れればよかったのだ。","ENG":"He should have taken the deal when we offered to increase his salary.","TWN":"給你漲簽約金的時候就該乖乖接受。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그나저나 증거조차 남지 않는 살인이라니 역시 쓸만하군.","JPN":"それにしても証拠が残らない殺人とは、やっぱり便利だな。","ENG":"Anyway, a murder without evidence. How useful.","TWN":"無論如何，這種連證據都不留的殺人手法，果然很有用。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"좋아, 이제 복귀해라. 침식체.","JPN":"いいぞ、もう復帰しろ。侵食体。","ENG":"All right. Now, come back. C.O.","TWN":"好了，現在回去吧，侵蝕體。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"인간. 궁금한 게 있다.","JPN":"人間。聞キタイコトアル。","ENG":"Human. I am curious.","TWN":"人類。我有。問題。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"같은 동족. 왜 죽여달라고 한 거지?","JPN":"同族。ナゼ殺シテクレト言ッタ？","ENG":"To kill your own kind. Why did you ask?","TWN":"同族。為什麼。要殺？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"침식체 주제에 질문도 할 줄 아나?","JPN":"侵食体の分際で、質問もできるのか？","ENG":"A C.O. asking questions?","TWN":"一個侵蝕體還會提問嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"합의체 놈들 대체 뭘 만들어 낸 거야. 인간 흉내라니, 역겹군.","JPN":"なんてものを作り出したんだ、合意体のやつら。人間の真似事なんて……反吐が出る。","ENG":"What did those bastards at the Northern Union create? Imitating a human? Disgusting.","TWN":"和議會的那幫傢伙到底造出了個什麼東西。模仿人類，真是噁心。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"좋아, 한 번만 답해주겠다.","JPN":"いいぞ、一度だけ答えてやる。","ENG":"Very well. I'll answer your question.","TWN":"好吧，我只回答你一次。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"인간은 대가 없이 행동하지 않아.","JPN":"人間は対価なしでは行動しない。","ENG":"Humans do not act without something in return.","TWN":"人類不會無償行動。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그리고 녀석은 자기 주제에 맞지 않는 대가를 요구했지.","JPN":"そしてやつは自分の身に余る対価を要求した。","ENG":"And the idiot you killed asked for more than he should have.","TWN":"而且那傢伙要求了不符合自己身份的報酬。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"대가?","JPN":"対価？","ENG":"Something in return?","TWN":"報酬？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"너도 마찬가지다. 침식체.","JPN":"お前もだ、侵食体。","ENG":"That goes the same for you, C.O.","TWN":"你也一樣。侵蝕體。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"네 목숨줄은 내가 쥐고 있어. 이 버튼 한 번이면, 핵이 파괴되어 소멸하게 되겠지.","JPN":"お前の命はこっちが握っている。このボタンを押せば核が壊され、お前は消滅する。","ENG":"I own you. With a click of a button, your core will shatter and you will be no more.","TWN":"你的生死存亡掌握在我的手中。只要按下這個按鈕，核心就會被摧毀，徹底消失。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그러니까 항상 네 놈의 주제를 잘 파악하도록 해.","JPN":"だからお前も身の程をわきまえるように。","ENG":"So, always know your place.","TWN":"所以你最好時刻認清自己的處境。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그런 게 처세술이라는 거다.","JPN":"それが世渡り上手、というものだ。","ENG":"It's what we call worldly wisdom.","TWN":"這就是所謂的處世之道。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"처세술?","JPN":"世渡リ？","ENG":"Worldly wisdom?","TWN":"處世之道？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};